import{_ as e,o as r,c as i,ag as s}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Barras colectoras","description":"","frontmatter":{},"headers":[],"relativePath":"es/power-systems/equipment/busbars.md","filePath":"es/power-systems/equipment/busbars.md"}'),o={name:"es/power-systems/equipment/busbars.md"};function n(t,a,c,l,d,p){return r(),i("div",null,[...a[0]||(a[0]=[s('<h1 id="barras-colectoras" tabindex="-1">Barras colectoras <a class="header-anchor" href="#barras-colectoras" aria-label="Permalink to &quot;Barras colectoras&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>Las barras colectoras son elementos conductores utilizados para distribuir energía eléctrica dentro de switchgear (celdas de media tensión), tableros de distribución y paneles de distribución.</p><p>Proporcionan un punto de conexión común donde múltiples circuitos pueden alimentarse desde una sola fuente.</p><p>Las barras colectoras están diseñadas para transportar altas corrientes con bajas pérdidas y alta confiabilidad.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>El propósito de las barras colectoras es:</p><ul><li>Distribuir energía de manera eficiente dentro del equipo eléctrico</li><li>Proporcionar una alternativa compacta y organizada a múltiples cables</li><li>Manejar altos niveles de corriente con caída de voltaje mínima</li><li>Simplificar las conexiones entre el suministro de entrada y los alimentadores de salida</li></ul><p>Forman la columna vertebral de la distribución interna de energía en los conjuntos eléctricos.</p><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>Las barras colectoras típicamente están fabricadas de cobre o aluminio y se montan dentro de gabinetes eléctricos.</p><p>La energía ingresa al sistema y se conduce a través de las barras colectoras, que actúan como una vía compartida para la corriente.</p><p>Los circuitos de salida se conectan a las barras colectoras a través de:</p><ul><li>Interruptores automáticos</li><li>Interruptores de desconexión</li><li>Puntos de derivación o conectores</li></ul><p>El área de la sección transversal de la barra colectora determina su capacidad de conducción de corriente.</p><p>El aislamiento y el espaciado se utilizan para prevenir cortocircuitos entre fases y a tierra.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>Las barras colectoras se utilizan en:</p><ul><li>Conjuntos de switchgear (celdas de media tensión)</li><li>Tableros de distribución y paneles de distribución</li><li>Centros de control de motores</li><li>Unidades de distribución de energía</li><li>Conexiones de alta corriente entre equipos</li></ul><p>Se encuentran comúnmente donde múltiples circuitos necesitan alimentarse desde un punto central.</p><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><ul><li><p><strong>Selección de material</strong><br> El cobre ofrece mayor conductividad y menor tamaño<br> El aluminio reduce el costo pero requiere secciones más grandes</p></li><li><p><strong>Capacidad de corriente</strong><br> Debe dimensionarse según la corriente de carga y los límites de elevación de temperatura</p></li><li><p><strong>Desempeño térmico</strong><br> La disipación de calor depende de la instalación, la ventilación y la agrupación</p></li><li><p><strong>Resistencia al cortocircuito</strong><br> Las barras colectoras deben soportar las fuerzas mecánicas durante condiciones de falla</p></li><li><p><strong>Aislamiento y espaciado</strong><br> Críticos para prevenir fallas fase a fase y fase a tierra</p></li><li><p><strong>Método de instalación</strong><br> Las barras rígidas o los sistemas de barras aisladas afectan la flexibilidad y la seguridad</p></li></ul><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><ul><li>Las conexiones flojas son una causa común de sobrecalentamiento y falla</li><li>La oxidación superficial puede aumentar la resistencia, especialmente en aluminio</li><li>Se requiere soporte adecuado para soportar las fuerzas electromagnéticas durante fallas</li><li>Los sistemas compactos de barras colectoras mejoran el uso del espacio pero requieren un diseño cuidadoso</li><li>La inspección regular ayuda a detectar puntos calientes y problemas de conexión de forma temprana</li></ul>',24)])])}const b=e(o,[["render",n]]);export{m as __pageData,b as default};
